{
  "pack": {
    "description": "By AnGrTea \n Using ONLY on map",
    "pack_format": 81
  }
}

scoreboard players set @s ray_success 1
execute positioned over motion_blocking run particle explosion ~ ~10 ~
execute if entity @s[team=red] positioned over motion_blocking run summon armor_stand ~ ~10 ~ {Invisible:1b,NoBasePlate:1b,Small:1b,DisabledSlots:1052688,equipment:{head:{id:amethyst_shard,components:{custom_model_data:{strings:[vines]}}}},Tags:["vines_red","vines"]}
execute if entity @s[team=blue] positioned over motion_blocking run summon armor_stand ~ ~10 ~ {Invisible:1b,NoBasePlate:1b,Small:1b,DisabledSlots:1052688,equipment:{head:{id:amethyst_shard,components:{custom_model_data:{strings:[vines]}}}},Tags:["vines_blue","vines"]}
schedule function ag001:abillity/active/vine/schelude_bypass 1t

execute if entity @s[team=red] rotated ~ ~ run summon marker ~ ~1 ~ {Tags:["at.bubbls","red"]}
execute if entity @s[team=blue] rotated ~ ~ run summon marker ~ ~1 ~ {Tags:["at.bubbls","blue"]}
playsound block.bubble_column.bubble_pop player @s ~ ~ ~ 7

$execute if entity @s[team=red] positioned ^$(random1) ^$(random2) ^ run summon marker ~ ~0.5 ~ {Tags:["at.magic1","red"]}
$execute if entity @s[team=blue] positioned ^$(random1) ^$(random2) ^ run summon marker ~ ~0.5 ~ {Tags:["at.magic1","blue"]}
$execute if entity @s[team=red] positioned ^$(random2) ^$(random1) ^ run summon marker ~ ~0.5 ~ {Tags:["at.magic1","red"]}
$execute if entity @s[team=blue] positioned ^$(random2) ^$(random1) ^ run summon marker ~ ~0.5 ~ {Tags:["at.magic1","blue"]}
playsound entity.ender_eye.death player @s

kill @n[type=item,nbt={Item:{id:"minecraft:carrot_on_a_stick"}}]
function ag001:abillity/subtitle/subtitle {symbol:"\uD003"}
function ag001:abillity/hands/ultimates/player_schelude_electricball

execute if entity @s[team=red] positioned ^ ^ ^0.5 run summon marker ~ ~0.5 ~ {Tags:["ult.electricball","red"]}
execute if entity @s[team=blue] positioned ^ ^ ^0.5 run summon marker ~ ~0.5 ~ {Tags:["ult.electricball","blue"]}
playsound entity.ender_eye.death player @s
execute as @e[type=marker,tag=ult.electricball] run function ag001:abillity/ultimate/electricball/ai_scheule_bypass

$scoreboard players add @a[team=blue] element-damage_bonus $(eldamage_multiple)
tag @a[team=blue] add wind_cause_elbonus
function ag001:elements/bonus/set {tick:160}

$scoreboard players add @a[team=red] element-damage_bonus $(eldamage_multiple)
tag @a[team=red] add wind_cause_elbonus
function ag001:elements/bonus/set {tick:160}

execute align zx run summon marker ~.5 ~ ~.5 {Tags:[wind_cause]}

function ag001:abillity/ultimate/wind_cause/end with storage config ultimate.windcause

execute if entity @s[team=blue] run function ag001:abillity/ultimate/wind_cause/elbonus-blue with storage config ultimate.windcause
execute if entity @s[team=red] run function ag001:abillity/ultimate/wind_cause/elbonus-red with storage config ultimate.windcause
function ag001:abillity/ultimate/wind_cause/ai with storage config ultimate.windcause
function ag001:abillity/subtitle/subtitle {symbol:"\uD004"}

$scoreboard players set @s element-electrical $(elcount)
tag @s add el.electrical
execute positioned ^-1 ^ ^-0.35 run summon area_effect_cloud ~ ~1 ~ {Radius:0,RadiusPerTick:-1,Duration:6,CustomName:[{text:"Электризован!",color:"#f6d75e"}],CustomNameVisible:1b,potion_contents:{custom_color:15787602},Tags:["el.displayer"]}

$scoreboard players set @s element-natural $(elcount)
tag @s add el.natural
execute positioned ^1 ^ ^0.35 run summon area_effect_cloud ~ ~1 ~ {Radius:0,RadiusPerTick:-1,Duration:6,CustomName:[{text:"Природа!",color:dark_green}],CustomNameVisible:1b,potion_contents:{custom_color:6192150},Tags:["el.displayer"]}

$scoreboard players set @s element-stopped $(elcount)
tag @s add el.stopped
execute positioned ^-1 ^ ^-0.35 run summon area_effect_cloud ~ ~1 ~ {Radius:0,RadiusPerTick:-1,Duration:6,CustomName:[{text:"Остановлен!",color:dark_gray}],CustomNameVisible:1b,potion_contents:{custom_color:1776667},Tags:["el.displayer"]}

scoreboard players add *times planting 1
execute if score *rounds planting matches 1 if score *times planting matches 1 run title @a title ""
execute if score *rounds planting matches 1 if score *times planting matches 1 run title @a subtitle {font:small_caps,"text":"15 секунд!","color":"yellow"}
execute if score *times planting matches 5 run title @a title ""
execute if score *times planting matches 5 run title @a subtitle {font:small_caps,"text":"10 секунд!","color":"yellow"}
execute if score *times planting matches 10 run title @a title ""
execute if score *times planting matches 10 run title @a subtitle {font:small_caps,"text":"5 секунд!","color":"yellow"}
execute if score *times planting matches 13 run title @a title ""
execute if score *times planting matches 13 run title @a subtitle {font:small_caps,"text":"3 секунды!","color":"yellow"}
execute if score *times planting matches 14 run title @a title ""
execute if score *times planting matches 14 run title @a subtitle {font:small_caps,"text":"2 секунды!","color":"red"}
execute if score *times planting matches 15 run title @a title ""
execute if score *times planting matches 15 run title @a subtitle {font:small_caps,"text":"1 секунда!","color":"red"}

execute if score *times planting matches ..15 run schedule function ag001:games/planting/timer 1s
execute if score *times planting matches 16 run function ag001:games/planting/timer_end
bossbar set planting players @a
execute if score *times planting matches 16.. run scoreboard players reset *times planting

scoreboard players add *times capture.point 1
title @s times 1s 4s 1s
execute if score *times capture.point matches 1 run title @a title ""
execute if score *times capture.point matches 1 run title @a subtitle {font:small_caps,"text":"15 секунд!","color":"yellow"}
execute if score *times capture.point matches 5 run title @a title ""
execute if score *times capture.point matches 5 run title @a subtitle {font:small_caps,"text":"10 секунд!","color":"yellow"}
execute if score *times capture.point matches 10 run title @a title ""
execute if score *times capture.point matches 10 run title @a subtitle {font:small_caps,"text":"5 секунд!","color":"yellow"}
execute if score *times capture.point matches 13 run title @a title ""
execute if score *times capture.point matches 13 run title @a subtitle {font:small_caps,"text":"3 секунды!","color":"yellow"}
execute if score *times capture.point matches 14 run title @a title ""
execute if score *times capture.point matches 14 run title @a subtitle {font:small_caps,"text":"2 секунды!","color":"red"}
execute if score *times capture.point matches 15 run title @a title ""
execute if score *times capture.point matches 15 run title @a subtitle {font:small_caps,"text":"1 секунда!","color":"red"}
execute if score *times capture.point matches ..14 run schedule function ag001:games/point/timer 1s
execute if score *times capture.point matches 15 run function ag001:games/point/timer_end

execute if score *times capture.point matches 15.. run scoreboard players reset *times capture.point

